const _map = new Map<number, CoupangCategory>();
for (const c of COUPANG_CATEGORIES) _map.set(c.code, c);

/** 쿠팡 카테고리코드로 필수옵션 조회 */
export function getCoupangCategoryByCode(code: number): CoupangCategory | undefined {
  return _map.get(code);
}

let _cachedPromptList: string | null = null;

/** Gemini 프롬프트용 카테고리 목록 문자열 (최초 호출 시 생성 후 캐시) */
export function buildCategoryListForPrompt(): string {
  return _cachedPromptList ??= COUPANG_CATEGORIES.map(c => c.code + ":" + c.path).join("\n");
}
